paramConversion.applyStepsToNormalizedParameterValue:
function applyStepsToNormalizedParameterValue(normalizedValue, steps) {
    if (steps == 1) {
        if (normalizedValue > 0) {
            normalizedValue = 1.;
        }
    } else {
        let oneStep = 1. / (steps - 1);
        let numberOfSteps = rnbo_fround(normalizedValue / oneStep * 1 / 1) * 1;
        normalizedValue = numberOfSteps * oneStep;
    }

    return normalizedValue;
}

paramConversion.convertToNormalizedParameterValue:
function convertToNormalizedParameterValue(index, value) {
    switch (index) {
    case 5:
    case 10:
        {
            value = (value < 0 ? 0 : (value > 1 ? 1 : value));
            let normalizedValue = (value - 0) / (1 - 0);
            return normalizedValue;
        }
    case 0:
        {
            value = (value < 0 ? 0 : (value > 1 ? 1 : value));
            let normalizedValue = (value - 0) / (1 - 0);

            {
                normalizedValue = this.applyStepsToNormalizedParameterValue(normalizedValue, 2);
            }

            return normalizedValue;
        }
    case 1:
        {
            value = (value < 0 ? 0 : (value > 2 ? 2 : value));
            let normalizedValue = (value - 0) / (2 - 0);

            {
                normalizedValue = this.applyStepsToNormalizedParameterValue(normalizedValue, 3);
            }

            return normalizedValue;
        }
    case 6:
        {
            value = (value < 0 ? 0 : (value > 3 ? 3 : value));
            let normalizedValue = (value - 0) / (3 - 0);

            {
                normalizedValue = this.applyStepsToNormalizedParameterValue(normalizedValue, 4);
            }

            return normalizedValue;
        }
    case 7:
        {
            value = (value < 0 ? 0 : (value > 2000 ? 2000 : value));
            let normalizedValue = (value - 0) / (2000 - 0);
            return normalizedValue;
        }
    case 2:
        {
            value = (value < 1 ? 1 : (value > 8000 ? 8000 : value));
            let normalizedValue = (value - 1) / (8000 - 1);
            return normalizedValue;
        }
    case 3:
        return value = rnbo_log2((value / 20 <= 0.0000000001 ? 0.0000000001 : value / 20)) / 10, (value <= 0.0 ? 0.0 : (value >= 1.0 ? 1.0 : value));
    case 4:
        {
            value = (value < -48 ? -48 : (value > 0 ? 0 : value));
            let normalizedValue = (value - -48) / (0 - -48);
            return normalizedValue;
        }
    case 8:
    case 9:
    case 11:
        {
            value = (value < 0.01 ? 0.01 : (value > 10000 ? 10000 : value));
            let normalizedValue = (value - 0.01) / (10000 - 0.01);
            return normalizedValue;
        }
    default:
        return value;
    }
}

paramConversion.convertFromNormalizedParameterValue:
function convertFromNormalizedParameterValue(index, value) {
    value = (value < 0 ? 0 : (value > 1 ? 1 : value));

    switch (index) {
    case 5:
    case 10:
        {
            {
                return 0 + value * (1 - 0);
            }
        }
    case 0:
        {
            {
                value = this.applyStepsToNormalizedParameterValue(value, 2);
            }

            {
                return 0 + value * (1 - 0);
            }
        }
    case 1:
        {
            {
                value = this.applyStepsToNormalizedParameterValue(value, 3);
            }

            {
                return 0 + value * (2 - 0);
            }
        }
    case 6:
        {
            {
                value = this.applyStepsToNormalizedParameterValue(value, 4);
            }

            {
                return 0 + value * (3 - 0);
            }
        }
    case 7:
        {
            {
                return 0 + value * (2000 - 0);
            }
        }
    case 2:
        {
            {
                return 1 + value * (8000 - 1);
            }
        }
    case 3:
        return fixnan(rnbo_pow(2, value * 10)) * 20;
    case 4:
        {
            {
                return -48 + value * (0 - -48);
            }
        }
    case 8:
    case 9:
    case 11:
        {
            {
                return 0.01 + value * (10000 - 0.01);
            }
        }
    default:
        return value;
    }
}

paramConversion.constrainParameterValue:
function constrainParameterValue(index, value) {
    var v = value;

    switch (index) {
    case 0:
        {
            v = (v > 1 ? 1 : (v < 0 ? 0 : v));

            {
                const oneStep = 1 / 1;
                const oneStepInv = (oneStep != 0 ? 1 / oneStep : 0);
                const numberOfSteps = rnbo_fround((v - 0) * oneStepInv * 1 / 1) * 1;
                v = numberOfSteps * oneStep + 0;
            }

            return v;
        }
    case 1:
        {
            v = (v > 2 ? 2 : (v < 0 ? 0 : v));

            {
                const oneStep = 2 / 2;
                const oneStepInv = (oneStep != 0 ? 1 / oneStep : 0);
                const numberOfSteps = rnbo_fround((v - 0) * oneStepInv * 1 / 1) * 1;
                v = numberOfSteps * oneStep + 0;
            }

            return v;
        }
    case 2:
        {
            v = (v > 8000 ? 8000 : (v < 1 ? 1 : v));
            return v;
        }
    case 3:
        {
            v = (v > 15000 ? 15000 : (v < 100 ? 100 : v));
            return v;
        }
    case 4:
        {
            v = (v > 0 ? 0 : (v < -48 ? -48 : v));
            return v;
        }
    case 5:
        {
            v = (v > 1 ? 1 : (v < 0 ? 0 : v));
            return v;
        }
    case 6:
        {
            v = (v > 3 ? 3 : (v < 0 ? 0 : v));

            {
                const oneStep = 3 / 3;
                const oneStepInv = (oneStep != 0 ? 1 / oneStep : 0);
                const numberOfSteps = rnbo_fround((v - 0) * oneStepInv * 1 / 1) * 1;
                v = numberOfSteps * oneStep + 0;
            }

            return v;
        }
    case 7:
        {
            v = (v > 2000 ? 2000 : (v < 0 ? 0 : v));
            return v;
        }
    case 8:
        {
            v = (v > 10000 ? 10000 : (v < 0.01 ? 0.01 : v));
            return v;
        }
    case 9:
        {
            v = (v > 10000 ? 10000 : (v < 0.01 ? 0.01 : v));
            return v;
        }
    case 10:
        {
            v = (v > 1 ? 1 : (v < 0 ? 0 : v));
            return v;
        }
    case 11:
        {
            v = (v > 10000 ? 10000 : (v < 0.01 ? 0.01 : v));
            return v;
        }
    default:
        return value;
    }
}
